content.text:
An interactive, responsive **Client Policy Issues Tracker** web application has been built to meet all specified trust and safety requirements, Polaris / Material Design 3 guidelines, and synchronization constraints.

It incorporates the real workspace team members as assignees, supports full CRUD workflows, applies active-focus master-detail tracking, and auto-polls the parent flat-file sync API for real-time collaboration.

### Features Included:
- **Comprehensive Fields**: Issue Description, Client Platform, Source Tool/Document, Severity (Critical, High, Medium, Low), Status, Assigned Lead (using real team members with initial circle avatars), Date Reported, and Resolution Details.
- **Robert Murdock's Polaris & M3 Aesthetics**: Ultra-minimal styling, clean 1px borders, generous whitespace, Google Sans typography, no distracting top headers/logos, and a plain white layout.
- **Smart Master-Detail Layout**: Fast inline list-detail navigation that avoids modal clutter.
- **Real-Time Synchronizer**: Client short-polling every 2 seconds utilizing `/api/sync` to coordinate edits seamlessly.

```html
<!-- index.html -->
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Client Policy Issues Tracker</title>
  <!-- Google Sans & Google Sans Text Fonts -->
  <link href="https://fonts.googleapis.com/css2?family=Google+Sans:wght@400;500;700&family=Google+Sans+Text:wght@400;500&display=swap" rel="stylesheet">
  <!-- Tailwind CSS CDN -->
  <script src="https://cdn.tailwindcss.com"></script>
  <script>
    tailwind.config = {
      theme: {
        extend: {
          fontFamily: {
            sans: ['"Google Sans"', '"Google Sans Text"', 'sans-serif'],
            body: ['"Google Sans Text"', 'sans-serif'],
          },
        },
      },
    }
  </script>
  <style>
    :root {
      --gemini-rail-icon-gap: 0px;
      --gemini-side-panel-padding-left: 16px;
      --gemini-side-panel-padding-right: 16px;
      --gemini-header-padding-left: 10px;
      --gemini-header-padding-right: 12px;
      --gemini-header-elements-gap: 8px;
    }
    body {
      font-family: "Google Sans Text", sans-serif;
      background-color: #ffffff;
      color: #1f1f1f;
    }
    h1, h2, h3, h4, h5, h6, button {
      font-family: "Google Sans", sans-serif;
    }
    .no-scrollbar::-webkit-scrollbar {
      display: none;
    }
    .no-scrollbar {
      -ms-overflow-style: none;
      scrollbar-width: none;
    }
  </style>
</head>
<body class="bg-white">

<div class="flex h-screen overflow-hidden bg-white">
  <!-- Left Side: Issues List & Filter controls -->
  <div class="w-full md:w-[420px] flex flex-col border-r border-slate-200 h-full bg-white select-none">

    <!-- Top Filter & Search Controls -->
    <div class="p-4 border-b border-slate-100 space-y-3">
      <div class="flex items-center justify-between">
        <span class="text-xs font-semibold text-slate-500 uppercase tracking-wider">Policy Issue Logs</span>
        <button id="new-issue-btn" onclick="startCreateNewIssue()" class="bg-[#0b57d0] hover:bg-[#0842a0] text-white px-3 py-1.5 rounded text-xs font-medium transition-colors flex items-center space-x-1">
          <span>+ New Issue</span>
        </button>
      </div>

      <!-- Search Input -->
      <div class="relative">
        <input type="text" id="search-input" oninput="renderIssuesList()" placeholder="Search client or description..." class="w-full pl-8 pr-3 py-1.5 text-xs bg-[#f0f4f9] rounded border border-transparent focus:bg-white focus:border-[#0b57d0] outline-none transition-all">
        <svg class="absolute left-2.5 top-2 h-4 w-4 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path>
        </svg>
      </div>

      <!-- Compact Select Filters -->
      <div class="grid grid-cols-3 gap-2">
        <select id="filter-severity" onchange="renderIssuesList()" class="bg-transparent border border-slate-200 rounded px-2 py-1 text-[11px] text-slate-600 outline-none">
          <option value="">All Severities</option>
          <option value="Critical">Critical</option>
          <option value="High">High</option>
          <option value="Medium">Medium</option>
          <option value="Low">Low</option>
        </select>
        <select id="filter-status" onchange="renderIssuesList()" class="bg-transparent border border-slate-200 rounded px-2 py-1 text-[11px] text-slate-600 outline-none">
          <option value="">All Statuses</option>
          <option value="Open">Open</option>
          <option value="Investigating">Investigating</option>
          <option value="Mitigation">Mitigation</option>
          <option value="Resolved">Resolved</option>
        </select>
        <select id="filter-client" onchange="renderIssuesList()" class="bg-transparent border border-slate-200 rounded px-2 py-1 text-[11px] text-slate-600 outline-none">
          <option value="">All Clients</option>
        </select>
      </div>
    </div>

    <!-- Scrollable Issues List -->
    <div id="issues-list" class="flex-1 overflow-y-auto divide-y divide-slate-100 no-scrollbar">
      <!-- Generated Dynamically -->
    </div>
  </div>

  <!-- Right Side: Details Pane / Editor Form -->
  <div id="details-pane" class="flex-1 flex flex-col h-full overflow-y-auto bg-white">
    <!-- Generated Dynamically -->
  </div>
</div>

<script>
  // Real Workspace Team Members Map
  const teamMembers = [
    { name: "Sakura Okoro", email: "sakura@example.com", initials: "SO", color: "#e8f0fe", textColor: "#1967d2" },
    { name: "Malik Harold", email: "malik@example.com", initials: "MH", color: "#fce8e6", textColor: "#c5221f" },
    { name: "Adam Lee", email: "adam@example.com", initials: "AL", color: "#e6f4ea", textColor: "#137333" }
  ];

  // Default initial set of issues synced from drive contexts
  const defaultIssues = [
    {
      id: "ISSUE-101",
      client: "Aegis AI",
      description: "LLM Jailbreak Escape: Zero-day prompt injection bypass on customer support chatbot returning prohibited toxicity responses.",
      source: "policy_issue_triage_framework.gdoc",
      severity: "High",
      status: "Mitigation",
      ownerEmail: "sakura@example.com",
      resolution: "Implemented initial system-level guardrails. Currently run adversarial testing against updated prompt templates.",
      dateReported: "2026-07-14"
    },
    {
      id: "ISSUE-102",
      client: "Veritas Social",
      description: "Harassment Classifier Bypass: Custom Unicode characters allow evasion of primary toxic intent filtering model.",
      source: "cross_client_policy_issues_matrix.csv",
      severity: "Medium",
      status: "Resolved",
      ownerEmail: "malik@example.com",
      resolution: "Retrained neural classifier on Unicode homoglyph datasets. Deployed model patch v2.1 to staging.",
      dateReported: "2026-07-15"
    },
    {
      id: "ISSUE-103",
      client: "Nexus Pay",
      description: "Credential Stuffing ATO Spike: Brute-force automated login spikes targeting authentication endpoints.",
      source: "client_policy_issues_tracker.doc",
      severity: "High",
      status: "Investigating",
      ownerEmail: "adam@example.com",
      resolution: "Currently evaluating rate limit rules, blocking high-risk subnets, and implementing emergency step-up MFA.",
      dateReported: "2026-07-12"
    },
    {
      id: "ISSUE-104",
      client: "Veritas Social",
      description: "CSAM PhotoDNA Hash Sync Discrepancy: PhotoDNA backend queue integration failing during peak traffic hours.",
      source: "client_policy_issues_deck.gslides",
      severity: "Critical",
      status: "Resolved",
      ownerEmail: "sakura@example.com",
      resolution: "Identified and patched buffer lock in core library handler. Automated recovery is now active.",
      dateReported: "2026-07-13"
    },
    {
      id: "ISSUE-105",
      client: "Aegis AI",
      description: "EU DSA Transparency Audit: Discrepancy report detailing gaps in transparency dashboards.",
      source: "cross_client_policy_issues_matrix.csv",
      severity: "Medium",
      status: "Open",
      ownerEmail: "adam@example.com",
      resolution: "",
      dateReported: "2026-07-10"
    }
  ];

  // Application State
  let issues = [];
  let selectedIssueId = null;

  // Real-time synchronization state configs
  const envId = window.__sandboxEnvId;
  const syncKey = "client_policy_issues_state_v1";

  // Escape HTML helper
  function escapeHTML(str) {
    if (!str) return '';
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#039;');
  }

  // Get member info safely
  function getMemberByEmail(email) {
    return teamMembers.find(m => m.email === email) || {
      name: email || "Unassigned",
      email: email,
      initials: email ? email.substring(0, 2).toUpperCase() : "?",
      color: "#f1f3f4",
      textColor: "#5f6368"
    };
  }

  // Check if form is currently active/focused to avoid jumping cursors on sync
  function isUserEditing() {
    const active = document.activeElement;
    if (!active) return false;
    return active.tagName === "INPUT" || active.tagName === "TEXTAREA" || active.tagName === "SELECT";
  }

  // Load state from local or API sync endpoints
  async function loadState() {
    if (envId) {
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && Array.isArray(json.data)) {
          applyNewIssuesData(json.data);
          return;
        }
      } catch (err) {
        console.error("Failed to fetch synced state:", err);
      }
    }

    // Fallback to localStorage
    const local = localStorage.getItem(syncKey);
    if (local) {
      try {
        applyNewIssuesData(JSON.parse(local));
      } catch (e) {
        applyNewIssuesData(defaultIssues);
      }
    } else {
      applyNewIssuesData(defaultIssues);
    }
  }

  function applyNewIssuesData(data) {
    const stringifiedNew = JSON.stringify(data);
    const stringifiedCurrent = JSON.stringify(issues);

    if (stringifiedNew !== stringifiedCurrent) {
      issues = data;
      updateClientFiltersDropdown();
      renderIssuesList();

      // Update details view if not editing
      if (selectedIssueId && !isUserEditing()) {
        renderDetailsPane();
      }
    }
  }

  // Save current issues array
  async function saveState() {
    localStorage.setItem(syncKey, JSON.stringify(issues));
    updateClientFiltersDropdown();

    if (envId) {
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: issues })
        });
      } catch (err) {
        console.error("Failed to save synced state:", err);
      }
    }
  }

  // Update unique clients dropdown
  function updateClientFiltersDropdown() {
    const clientSelect = document.getElementById("filter-client");
    if (!clientSelect) return;
    const currentVal = clientSelect.value;

    const clients = [...new Set(issues.map(item => item.client))].filter(Boolean).sort();

    let html = `<option value="">All Clients</option>`;
    clients.forEach(c => {
      html += `<option value="${escapeHTML(c)}">${escapeHTML(c)}</option>`;
    });
    clientSelect.innerHTML = html;
    clientSelect.value = currentVal;
  }

  // Render Left Side Lists
  function renderIssuesList() {
    const container = document.getElementById("issues-list");
    if (!container) return;

    const searchVal = document.getElementById("search-input").value.toLowerCase();
    const filterSev = document.getElementById("filter-severity").value;
    const filterStat = document.getElementById("filter-status").value;
    const filterClient = document.getElementById("filter-client").value;

    // Filter Issues list
    let filtered = issues.filter(issue => {
      const matchSearch = issue.client.toLowerCase().includes(searchVal) || 
                          issue.description.toLowerCase().includes(searchVal) ||
                          issue.id.toLowerCase().includes(searchVal);
      const matchSev = !filterSev || issue.severity === filterSev;
      const matchStat = !filterStat || issue.status === filterStat;
      const matchClient = !filterClient || issue.client === filterClient;

      return matchSearch && matchSev && matchStat && matchClient;
    });

    // Sort Descending by ID
    filtered.sort((a, b) => b.id.localeCompare(a.id));

    if (filtered.length === 0) {
      container.innerHTML = `
        <div class="p-8 text-center text-slate-400 text-xs">
          No policy issues found matching filters.
        </div>
      `;
      return;
    }

    let html = "";
    filtered.forEach(issue => {
      const member = getMemberByEmail(issue.ownerEmail);
      const isActive = selectedIssueId === issue.id;

      const activeClass = isActive 
        ? 'bg-[#e8f0fe] border-l-[3px] border-l-[#0b57d0]' 
        : 'hover:bg-slate-50 border-l-[3px] border-l-transparent';

      // Severity display tags styling parameters
      let severityClass = "text-slate-500";
      if (issue.severity === "Critical") severityClass = "text-red-600 font-semibold";
      else if (issue.severity === "High") severityClass = "text-orange-600 font-semibold";
      else if (issue.severity === "Medium") severityClass = "text-blue-600 font-semibold";

      let statusClass = "text-slate-500";
      if (issue.status === "Resolved") statusClass = "text-green-600 font-medium";
      else if (issue.status === "Mitigation") statusClass = "text-purple-600 font-medium";
      else if (issue.status === "Investigating") statusClass = "text-amber-600 font-medium";

      html += `
        <div onclick="selectIssue('${issue.id}')" class="p-4 cursor-pointer transition-colors ${activeClass} border-b border-slate-100 flex flex-col space-y-1">
          <div class="flex items-center justify-between">
            <span class="text-[10px] font-mono text-slate-400 tracking-wider font-semibold">${issue.id}</span>
            <span class="text-[10px] text-slate-400">${issue.dateReported}</span>
          </div>
          <div class="text-sm font-medium text-slate-800">${escapeHTML(issue.client)}</div>
          <p class="text-xs text-slate-500 line-clamp-2 mt-0.5 leading-relaxed">${escapeHTML(issue.description)}</p>

          <div class="flex items-center justify-between mt-2 pt-1">
            <div class="flex space-x-2 text-[11px] items-center">
              <span class="${severityClass}">${issue.severity}</span>
              <span class="text-slate-300">•</span>
              <span class="${statusClass}">${issue.status}</span>
            </div>

            <!-- Custom Initials Avatar -->
            <div class="flex items-center space-x-1" title="${escapeHTML(member.name)}">
              <div class="w-5 h-5 rounded-full flex items-center justify-center text-[9px] font-bold" style="background-color: ${member.color}; color: ${member.textColor};">
                ${member.initials}
              </div>
            </div>
          </div>
        </div>
      `;
    });

    container.innerHTML = html;
  }

  // Handle row selection
  function selectIssue(id) {
    selectedIssueId = id;
    renderIssuesList();
    renderDetailsPane();
  }

  function startCreateNewIssue() {
    selectedIssueId = "NEW";
    renderIssuesList();
    renderDetailsPane();
  }

  // Cancel edit sequence
  function cancelEdit() {
    selectedIssueId = null;
    renderIssuesList();
    renderDetailsPane();
  }

  // Render Right Side Details / Editor Pane
  function renderDetailsPane() {
    const pane = document.getElementById("details-pane");
    if (!pane) return;

    if (!selectedIssueId) {
      pane.innerHTML = `
        <div class="flex-1 flex flex-col items-center justify-center p-8 text-slate-400 text-center h-full select-none">
          <svg class="w-12 h-12 mb-3 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path>
          </svg>
          <p class="text-sm font-medium text-slate-600">No issue selected</p>
          <p class="text-xs text-slate-400 mt-1">Select an issue from the list or create a new issue to view and edit triage logs.</p>
        </div>
      `;
      return;
    }

    let isNew = selectedIssueId === "NEW";
    let issue = null;

    if (isNew) {
      // Create fresh blank setup with today's date
      const today = new Date().toISOString().split('T')[0];
      issue = {
        id: "",
        client: "",
        description: "",
        source: "",
        severity: "High",
        status: "Open",
        ownerEmail: "sakura@example.com",
        resolution: "",
        dateReported: today
      };
    } else {
      issue = issues.find(i => i.id === selectedIssueId);
      if (!issue) {
        pane.innerHTML = `
          <div class="p-8 text-center text-red-500 text-sm">
            Error: Issue data not found or has been deleted by another user.
          </div>
        `;
        return;
      }
    }

    // Determine current Workspace metadata
    const activeWorkspaceName = window.__sandboxWorkspaceName || "Active Workspace";

    pane.innerHTML = `
      <div class="p-6 max-w-2xl w-full mx-auto space-y-5">

        <!-- Header Info -->
        <div class="flex items-center justify-between border-b border-slate-100 pb-3">
          <div>
            <span class="text-[10px] text-slate-400 font-mono tracking-wider font-semibold uppercase">
              ${isNew ? 'New Entry Creation' : `Issue: ${issue.id}`}
            </span>
            <h2 class="text-base font-medium text-slate-800 mt-0.5">
              ${isNew ? 'Log Policy Violation Issue' : 'Edit Violation Details'}
            </h2>
          </div>

          <div class="flex items-center space-x-2 text-[11px] text-slate-400">
            <span class="w-2 h-2 rounded-full bg-emerald-500 inline-block"></span>
            <span>${activeWorkspaceName}</span>
          </div>
        </div>

        <form id="issue-form" class="space-y-4" onsubmit="handleFormSubmit(event)">
          <input type="hidden" id="form-issue-id" value="${issue.id}">

          <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
            <!-- Client Name -->
            <div class="flex flex-col space-y-1">
              <label for="form-client" class="text-xs font-semibold text-slate-600">Client Platform <span class="text-red-500">*</span></label>
              <input type="text" id="form-client" required class="border border-slate-200 rounded px-3 py-1.5 text-xs focus:border-[#0b57d0] focus:outline-none focus:ring-1 focus:ring-[#0b57d0]" value="${escapeHTML(issue.client)}" placeholder="e.g. Aegis AI">
            </div>

            <!-- Source Tool -->
            <div class="flex flex-col space-y-1">
              <label for="form-source" class="text-xs font-semibold text-slate-600">Source Tool / Doc</label>
              <input type="text" id="form-source" class="border border-slate-200 rounded px-3 py-1.5 text-xs focus:border-[#0b57d0] focus:outline-none focus:ring-1 focus:ring-[#0b57d0]" value="${escapeHTML(issue.source || '')}" placeholder="e.g. policy_issue_triage_framework.gdoc">
            </div>
          </div>

          <div class="grid grid-cols-1 md:grid-cols-3 gap-4">
            <!-- Severity -->
            <div class="flex flex-col space-y-1">
              <label for="form-severity" class="text-xs font-semibold text-slate-600">Severity Level</label>
              <select id="form-severity" class="border border-slate-200 rounded px-3 py-1.5 text-xs bg-white focus:border-[#0b57d0] focus:outline-none">
                <option value="Critical" ${issue.severity === 'Critical' ? 'selected' : ''}>Critical</option>
                <option value="High" ${issue.severity === 'High' ? 'selected' : ''}>High</option>
                <option value="Medium" ${issue.severity === 'Medium' ? 'selected' : ''}>Medium</option>
                <option value="Low" ${issue.severity === 'Low' ? 'selected' : ''}>Low</option>
              </select>
            </div>

            <!-- Status -->
            <div class="flex flex-col space-y-1">
              <label for="form-status" class="text-xs font-semibold text-slate-600">Resolution Status</label>
              <select id="form-status" class="border border-slate-200 rounded px-3 py-1.5 text-xs bg-white focus:border-[#0b57d0] focus:outline-none">
                <option value="Open" ${issue.status === 'Open' ? 'selected' : ''}>Open</option>
                <option value="Investigating" ${issue.status === 'Investigating' ? 'selected' : ''}>Investigating</option>
                <option value="Mitigation" ${issue.status === 'Mitigation' ? 'selected' : ''}>Mitigation</option>
                <option value="Resolved" ${issue.status === 'Resolved' ? 'selected' : ''}>Resolved</option>
              </select>
            </div>

            <!-- Owner -->
            <div class="flex flex-col space-y-1">
              <label for="form-owner" class="text-xs font-semibold text-slate-600">Assigned T&S Lead</label>
              <select id="form-owner" class="border border-slate-200 rounded px-3 py-1.5 text-xs bg-white focus:border-[#0b57d0] focus:outline-none">
                ${teamMembers.map(m => `<option value="${m.email}" ${issue.ownerEmail === m.email ? 'selected' : ''}>${m.name} (${m.email})</option>`).join('')}
              </select>
            </div>
          </div>

          <!-- Date -->
          <div class="flex flex-col space-y-1 w-full md:w-1/2">
            <label for="form-date" class="text-xs font-semibold text-slate-600">Date Reported</label>
            <input type="date" id="form-date" required class="border border-slate-200 rounded px-3 py-1.5 text-xs focus:border-[#0b57d0] focus:outline-none focus:ring-1 focus:ring-[#0b57d0]" value="${issue.dateReported}">
          </div>

          <!-- Issue Description -->
          <div class="flex flex-col space-y-1">
            <label for="form-description" class="text-xs font-semibold text-slate-600">Issue Description <span class="text-red-500">*</span></label>
            <textarea id="form-description" rows="3" required class="border border-slate-200 rounded px-3 py-1.5 text-xs focus:border-[#0b57d0] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] resize-none" placeholder="Provide description of jailbreaks, content escapes or policy risks...">${escapeHTML(issue.description)}</textarea>
          </div>

          <!-- Resolution Details -->
          <div class="flex flex-col space-y-1">
            <label for="form-resolution" class="text-xs font-semibold text-slate-600">Resolution Details</label>
            <textarea id="form-resolution" rows="3" class="border border-slate-200 rounded px-3 py-1.5 text-xs focus:border-[#0b57d0] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] resize-none" placeholder="Remediation steps, safety fine-tuning deployments, or policy update confirmations...">${escapeHTML(issue.resolution || '')}</textarea>
          </div>

          <!-- Actions Footer bar -->
          <div class="flex items-center justify-between pt-4 border-t border-slate-100">
            <div>
              ${!isNew ? `
                <button type="button" onclick="deleteIssue('${issue.id}')" class="text-red-600 hover:text-red-800 text-xs font-medium flex items-center space-x-1">
                  <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path>
                  </svg>
                  <span>Delete</span>
                </button>
              ` : '<div></div>'}
            </div>

            <div class="flex items-center space-x-2">
              <button type="button" onclick="cancelEdit()" class="border border-slate-200 hover:bg-slate-50 text-slate-700 px-3.5 py-1.5 rounded text-xs font-medium transition-colors">
                Cancel
              </button>
              <button type="submit" class="bg-[#0b57d0] hover:bg-[#0842a0] text-white px-3.5 py-1.5 rounded text-xs font-medium transition-colors">
                ${isNew ? 'Create Issue' : 'Save Changes'}
              </button>
            </div>
          </div>
        </form>
      </div>
    `;
  }

  // Handle Create or Update operations
  async function handleFormSubmit(event) {
    event.preventDefault();

    const idVal = document.getElementById("form-issue-id").value;
    const clientVal = document.getElementById("form-client").value.trim();
    const sourceVal = document.getElementById("form-source").value.trim();
    const severityVal = document.getElementById("form-severity").value;
    const statusVal = document.getElementById("form-status").value;
    const ownerEmailVal = document.getElementById("form-owner").value;
    const dateVal = document.getElementById("form-date").value;
    const descriptionVal = document.getElementById("form-description").value.trim();
    const resolutionVal = document.getElementById("form-resolution").value.trim();

    if (selectedIssueId === "NEW") {
      // Find maximum ID to generate next sequentially
      let maxNum = 100;
      issues.forEach(i => {
        const match = i.id.match(/^ISSUE-(\d+)$/);
        if (match) {
          const num = parseInt(match[1]);
          if (num > maxNum) maxNum = num;
        }
      });
      const nextId = `ISSUE-${maxNum + 1}`;

      const newIssue = {
        id: nextId,
        client: clientVal,
        source: sourceVal,
        severity: severityVal,
        status: statusVal,
        ownerEmail: ownerEmailVal,
        dateReported: dateVal,
        description: descriptionVal,
        resolution: resolutionVal
      };

      issues.push(newIssue);
      selectedIssueId = nextId;
    } else {
      const idx = issues.findIndex(i => i.id === idVal);
      if (idx !== -1) {
        issues[idx].client = clientVal;
        issues[idx].source = sourceVal;
        issues[idx].severity = severityVal;
        issues[idx].status = statusVal;
        issues[idx].ownerEmail = ownerEmailVal;
        issues[idx].dateReported = dateVal;
        issues[idx].description = descriptionVal;
        issues[idx].resolution = resolutionVal;
      }
    }

    await saveState();
    renderIssuesList();
    renderDetailsPane();
  }

  // Handle Delete operation
  async function deleteIssue(id) {
    if (!confirm(`Are you sure you want to delete policy issue ${id}?`)) {
      return;
    }

    issues = issues.filter(i => i.id !== id);
    selectedIssueId = null;

    await saveState();
    renderIssuesList();
    renderDetailsPane();
  }

  // Initialization
  async function init() {
    await loadState();

    // Auto short poll every 2 seconds for flawless multi-user sync
    if (envId) {
      setInterval(loadState, 2000);
    }
  }

  window.addEventListener('DOMContentLoaded', init);
</script>
